import React, { useState } from 'react';

const WEATHER_API_KEY = 'YOUR_OPENWEATHERMAP_API_KEY'; // Replace with real key

const MOCK_WEATHER = {
  city: 'Hyderabad',
  temp: 32,
  feelsLike: 36,
  humidity: 68,
  windSpeed: 12,
  condition: 'Partly Cloudy',
  icon: '⛅',
  forecast: [
    { day: 'Today', icon: '⛅', high: 32, low: 24, rain: '20%' },
    { day: 'Tomorrow', icon: '🌧️', high: 28, low: 22, rain: '75%' },
    { day: 'Wed', icon: '🌦️', high: 29, low: 23, rain: '60%' },
    { day: 'Thu', icon: '☀️', high: 33, low: 25, rain: '5%' },
    { day: 'Fri', icon: '☀️', high: 35, low: 26, rain: '0%' },
  ],
  farmingTips: [
    '🌧️ Rain expected tomorrow — delay fertilizer application by 2 days',
    '💧 High humidity: Watch for fungal diseases on rice crops',
    '🌬️ Moderate winds: Good for spraying pesticides today',
    '☀️ Clear days Thursday-Friday: Ideal for harvesting',
  ]
};

export default function WeatherDashboard({ farmer }) {
  const [city, setCity] = useState(farmer?.city || 'Hyderabad');
  const [weather, setWeather] = useState(MOCK_WEATHER);
  const [loading, setLoading] = useState(false);

  const fetchWeather = async () => {
    setLoading(true);
    // Demo: show mock data with entered city name
    setTimeout(() => {
      setWeather({ ...MOCK_WEATHER, city });
      setLoading(false);
    }, 800);
  };

  return (
    <div>
      {/* Search Bar */}
      <div style={styles.searchBar}>
        <input
          style={styles.searchInput}
          value={city}
          onChange={(e) => setCity(e.target.value)}
          placeholder="Enter city name..."
          onKeyDown={(e) => e.key === 'Enter' && fetchWeather()}
        />
        <button className="btn btn-primary" onClick={fetchWeather} disabled={loading}>
          {loading ? <span className="spinner" style={{width:16,height:16}} /> : '🔍 Get Weather'}
        </button>
      </div>

      {/* Main Weather Card */}
      <div style={styles.mainCard}>
        <div style={styles.mainLeft}>
          <div style={styles.cityName}>📍 {weather.city}</div>
          <div style={styles.bigTemp}>{weather.temp}°C</div>
          <div style={styles.condition}>{weather.icon} {weather.condition}</div>
          <div style={styles.feelsLike}>Feels like {weather.feelsLike}°C</div>
        </div>
        <div style={styles.mainRight}>
          <div style={styles.statBox}>
            <div style={styles.statLabel}>💧 Humidity</div>
            <div style={styles.statValue}>{weather.humidity}%</div>
          </div>
          <div style={styles.statBox}>
            <div style={styles.statLabel}>💨 Wind</div>
            <div style={styles.statValue}>{weather.windSpeed} km/h</div>
          </div>
        </div>
      </div>

      {/* 5-Day Forecast */}
      <div style={styles.sectionTitle}>📅 5-Day Forecast</div>
      <div style={styles.forecast}>
        {weather.forecast.map((day, i) => (
          <div key={i} style={{
            ...styles.forecastCard,
            background: i === 0 ? '#E8F5E9' : 'white',
            border: i === 0 ? '2px solid #4CAF50' : '1px solid #C8E6C9',
          }}>
            <div style={styles.forecastDay}>{day.day}</div>
            <div style={styles.forecastIcon}>{day.icon}</div>
            <div style={styles.forecastTemp}>{day.high}°/{day.low}°</div>
            <div style={styles.forecastRain}>🌧️ {day.rain}</div>
          </div>
        ))}
      </div>

      {/* Farming Tips */}
      <div style={styles.sectionTitle}>🌾 Weather-Based Farming Tips</div>
      <div style={{ display: 'flex', flexDirection: 'column', gap: 10 }}>
        {weather.farmingTips.map((tip, i) => (
          <div key={i} className="alert alert-info" style={{ marginBottom: 0 }}>
            {tip}
          </div>
        ))}
      </div>
    </div>
  );
}

const styles = {
  searchBar: { display: 'flex', gap: 12, marginBottom: 20 },
  searchInput: {
    flex: 1, padding: '10px 16px', borderRadius: 8,
    border: '2px solid #C8E6C9', fontFamily: "'Poppins', sans-serif",
    fontSize: '0.95rem', outline: 'none',
  },
  mainCard: {
    background: 'linear-gradient(135deg, #1B5E20, #2E7D32)',
    borderRadius: 16, padding: '28px 32px', color: 'white',
    display: 'flex', justifyContent: 'space-between',
    alignItems: 'center', marginBottom: 24,
  },
  mainLeft: {},
  cityName: { fontSize: '1rem', opacity: 0.85, marginBottom: 8 },
  bigTemp: { fontSize: '3.5rem', fontWeight: 800, fontFamily: "'Nunito', sans-serif", lineHeight: 1 },
  condition: { fontSize: '1.1rem', marginTop: 8, opacity: 0.9 },
  feelsLike: { fontSize: '0.85rem', opacity: 0.7, marginTop: 4 },
  mainRight: { display: 'flex', gap: 20 },
  statBox: { textAlign: 'center', background: 'rgba(255,255,255,0.12)', borderRadius: 12, padding: '16px 20px' },
  statLabel: { fontSize: '0.8rem', opacity: 0.75, marginBottom: 6 },
  statValue: { fontSize: '1.4rem', fontWeight: 700 },
  sectionTitle: {
    fontFamily: "'Nunito', sans-serif", fontWeight: 800,
    fontSize: '1rem', color: '#1B5E20', marginBottom: 14, marginTop: 4,
  },
  forecast: { display: 'flex', gap: 12, marginBottom: 24, flexWrap: 'wrap' },
  forecastCard: {
    flex: 1, minWidth: 90, textAlign: 'center', borderRadius: 12,
    padding: '14px 10px',
  },
  forecastDay: { fontSize: '0.8rem', fontWeight: 700, color: '#5D7A5C', marginBottom: 6 },
  forecastIcon: { fontSize: 28, marginBottom: 6 },
  forecastTemp: { fontSize: '0.85rem', fontWeight: 600, color: '#1B2B1A', marginBottom: 4 },
  forecastRain: { fontSize: '0.78rem', color: '#1565C0' },
};
